const config = $input.first().json;

// Build list of pages — skip any that have no URL
const pages = [
  { url: config.page1Url, name: config.page1Name },
  { url: config.page2Url, name: config.page2Name },
  { url: config.page3Url, name: config.page3Name }
].filter(p => p.url && p.url.startsWith('http'));

if (pages.length === 0) {
  throw new Error('No valid URLs found. Please submit at least one URL starting with http.');
}

// Return one item per page — the rest of the workflow runs once for each page
return pages.map((page, index) => ({
  json: {
    pageUrl: page.url,
    pageName: page.name,
    pageIndex: index + 1,
    totalPages: pages.length,
    businessType: config.businessType,
    auditorName: config.auditorName,
    sheetId: config.sheetId,
    sheetName: config.sheetName,
    alertEmail: config.alertEmail,
    senderName: config.senderName,
    scoreThreshold: parseInt(config.scoreThreshold) || 6
  }
}));

const html = $input.first().json;
const pageData = $('3. Code — Build Pages List').item.json;

// Get raw HTML as a string
let rawHtml = '';
if (typeof html === 'string') {
  rawHtml = html;
} else if (html?.data) {
  rawHtml = typeof html.data === 'string' ? html.data : JSON.stringify(html.data);
} else {
  rawHtml = JSON.stringify(html);
}

if (!rawHtml || rawHtml.length < 100) {
  throw new Error('Page returned no usable content for: ' + pageData.pageUrl);
}

// Remove script and style blocks
let cleanText = rawHtml
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<!--[\s\S]*?-->/g, '')
  .replace(/<\/(div|p|li|h[1-6]|section|article|header|footer|nav|main)>/gi, '\n')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/\s{3,}/g, '\n\n')
  .trim();

const wasTruncated = cleanText.length > 4000;
cleanText = cleanText.substring(0, 4000);
if (wasTruncated) cleanText += '\n[Content cut off at 4000 characters]';

return [{
  json: {
    pageUrl: pageData.pageUrl,
    pageName: pageData.pageName,
    businessType: pageData.businessType,
    auditorName: pageData.auditorName,
    pageContent: cleanText,
    sheetId: pageData.sheetId,
    sheetName: pageData.sheetName,
    alertEmail: pageData.alertEmail,
    senderName: pageData.senderName,
    scoreThreshold: pageData.scoreThreshold
  }
}];

