{
  "type": "object",
  "properties": {
    "overallScore": { "type": "number", "description": "CRO score from 1 to 10" },
    "grade": { "type": "string", "description": "F, D, C, B, A, or A+" },
    "ctaStrength": { "type": "number", "description": "CTA quality from 1 to 10" },
    "trustScore": { "type": "number", "description": "Trust and social proof from 1 to 10" },
    "messageClarity": { "type": "number", "description": "Value proposition clarity from 1 to 10" },
    "topIssue": { "type": "string", "description": "The biggest conversion problem on the page" },
    "quickWin": { "type": "string", "description": "The single fastest fix to boost conversions" },
    "fixList": { "type": "array", "items": { "type": "string" }, "description": "List of 5 specific improvements" },
    "priority": { "type": "string", "description": "CRITICAL, HIGH, MEDIUM, or LOW" }
  },
  "required": ["overallScore", "grade", "ctaStrength", "trustScore", "messageClarity", "topIssue", "quickWin", "fixList", "priority"]
}

