const aiOutput = $input.first().json.output;
const pageData = $('5. Code — Clean HTML to Text').item.json;

const score = aiOutput?.overallScore || 0;
const grade = aiOutput?.grade || 'N/A';
const priority = aiOutput?.priority || 'HIGH';
const threshold = pageData.scoreThreshold || 6;

const scoreEmoji = score >= 8 ? 'Good' : score >= 6 ? 'Average' : score >= 4 ? 'Poor' : 'Critical';

const priorityLabel = {
  'LOW': 'Low',
  'MEDIUM': 'Medium',
  'HIGH': 'High',
  'CRITICAL': 'Critical'
}[priority] || 'High';

const fixListForSheet = (aiOutput?.fixList || []).map((f, i) => (i + 1) + '. ' + f).join(' | ');
const fixListForEmail = (aiOutput?.fixList || []).map((f, i) => (i + 1) + '. ' + f).join('\n');

const today = new Date().toLocaleDateString('en-GB', {
  day: '2-digit', month: 'short', year: 'numeric'
});
const loggedAt = new Date().toISOString().replace('T', ' ').substring(0, 16);

const emailSubject = 'CRO Alert — ' + pageData.pageName + ' scored ' + score + ' out of 10 (' + grade + ')';
const emailBody =
  'Hi ' + pageData.senderName + ',\n\n' +
  'One of your landing pages scored below your alert threshold.\n\n' +
  'Page name: ' + pageData.pageName + '\n' +
  'Page URL: ' + pageData.pageUrl + '\n' +
  'CRO score: ' + score + ' out of 10 — ' + grade + ' — ' + scoreEmoji + '\n' +
  'Priority level: ' + priorityLabel + '\n\n' +
  'Top issue:\n' + (aiOutput?.topIssue || 'Not available') + '\n\n' +
  'Fastest fix:\n' + (aiOutput?.quickWin || 'Not available') + '\n\n' +
  '5 specific fixes for this page:\n' + fixListForEmail + '\n\n' +
  'Sub-scores:\n' +
  'CTA strength: ' + (aiOutput?.ctaStrength || 'N/A') + ' out of 10\n' +
  'Trust score: ' + (aiOutput?.trustScore || 'N/A') + ' out of 10\n' +
  'Message clarity: ' + (aiOutput?.messageClarity || 'N/A') + ' out of 10\n\n' +
  'Please fix this page before your next campaign.\n\n' +
  'Best regards,\n' + pageData.senderName;

return [{
  json: {
    date: today,
    pageUrl: pageData.pageUrl,
    pageName: pageData.pageName,
    croScore: score + ' out of 10 — ' + scoreEmoji,
    grade: grade,
    topIssue: aiOutput?.topIssue || 'Not available',
    quickWin: aiOutput?.quickWin || 'Not available',
    ctaStrength: (aiOutput?.ctaStrength || 0) + ' out of 10',
    trustScore: (aiOutput?.trustScore || 0) + ' out of 10',
    messageClarity: (aiOutput?.messageClarity || 0) + ' out of 10',
    priority: priorityLabel,
    fixList: fixListForSheet,
    auditorName: pageData.auditorName,
    loggedAt: loggedAt,
    needsAlert: score < threshold,
    rawScore: score,
    emailSubject: emailSubject,
    emailBody: emailBody,
    alertEmail: pageData.alertEmail,
    sheetId: pageData.sheetId,
    sheetName: pageData.sheetName
  }
}];
